      reviews = parseCSV(csvData);
      productName = body.productName || "Uploaded Product";
    } else {
      return NextResponse.json(
        { success: false, error: "Invalid request. Provide URL or CSV data." },
        { status: 400 }
      );
    }

    if (reviews.length === 0) {
      return NextResponse.json(
        {
          success: false,
          error: "No reviews found. Please check your input and try again.",
        },
        { status: 400 }
      );
    }

    // Analyze sentiment with Amazon Comprehend
    const enrichedReviews = await analyzeSentiment(reviews);

    // Compute analytics
    const analytics = computeAnalytics(enrichedReviews);

    // Sort reviews by date (newest first)
    const dates = enrichedReviews
      .map((r) => r.date)
      .filter(Boolean)
      .sort();

    const metadata: ReviewMetadata = {
      platform,
      productName,
      productUrl,
      totalReviews: enrichedReviews.length,
      averageRating: analytics.averageRating,
      dateRange: {
        earliest: dates[0] || "Unknown",
        latest: dates[dates.length - 1] || "Unknown",
      },
      scrapedAt: new Date().toISOString(),
    };

    // Store session
    const sessionId = uuidv4();
    const session: ReviewSession = {
      sessionId,
      reviews: enrichedReviews,
      metadata,
      analytics,
    };
    setSession(sessionId, session);

    return NextResponse.json({
      success: true,
      sessionId,
      metadata,
      reviewCount: enrichedReviews.length,
    });
  } catch (error) {
    console.error("Ingest error:", error);
    return NextResponse.json(
      {
        success: false,
        error: "Failed to process reviews. Please try again.",
      },
      { status: 500 }
    );
  }
}

"use client";

import { Star, MessageSquare, Calendar, TrendingUp } from "lucide-react";
import { ReviewMetadata, AnalyticsData } from "@/types";

interface StatsCardsProps {
  metadata: ReviewMetadata;
  analytics: AnalyticsData;
}

export default function StatsCards({ metadata, analytics }: StatsCardsProps) {
  const sentimentTotal =
    analytics.sentimentBreakdown.positive +
    analytics.sentimentBreakdown.negative +
    analytics.sentimentBreakdown.neutral +
    analytics.sentimentBreakdown.mixed;

  const positivePercent =
    sentimentTotal > 0
      ? Math.round((analytics.sentimentBreakdown.positive / sentimentTotal) * 100)
      : 0;

  const stats = [
    {
      label: "Total Reviews",
      value: metadata.totalReviews.toLocaleString(),
      icon: MessageSquare,
      gradient: "from-violet-500 to-purple-600",
      glow: "shadow-violet-500/20",
    },
    {
      label: "Average Rating",
      value: analytics.averageRating.toFixed(1),
      icon: Star,
      gradient: "from-amber-500 to-orange-600",
      glow: "shadow-amber-500/20",
      suffix: "/ 5",
    },
    {
      label: "Positive Sentiment",
      value: `${positivePercent}%`,
      icon: TrendingUp,
      gradient: "from-emerald-500 to-green-600",
      glow: "shadow-emerald-500/20",
    },
    {
      label: "Date Range",
      value:
        metadata.dateRange.earliest === "Unknown"
          ? "N/A"
          : metadata.dateRange.earliest.slice(0, 10),
      icon: Calendar,
      gradient: "from-cyan-500 to-blue-600",
      glow: "shadow-cyan-500/20",
      suffix:
        metadata.dateRange.latest !== "Unknown"
          ? ` — ${metadata.dateRange.latest.slice(0, 10)}`
          : "",
    },
  ];

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
      {stats.map((stat, i) => {
        const Icon = stat.icon;
        return (
          <div
            key={stat.label}
            className="glass-card rounded-xl p-5 animate-fade-up"
            style={{ animationDelay: `${i * 0.1}s`, animationFillMode: 'backwards' }}
          >
            <div className="flex items-center gap-3.5">
              <div
                className={`w-11 h-11 rounded-xl bg-linear-to-br ${stat.gradient} flex items-center justify-center shadow-lg ${stat.glow}`}
              >
                <Icon className="w-5 h-5 text-white" />
              </div>
              <div>
                <p className="text-xs text-white/40 uppercase tracking-wider">
                  {stat.label}
                </p>
                <p className="text-2xl font-bold text-white/90">
                  {stat.value}
                  {stat.suffix && (
                    <span className="text-sm font-normal text-white/30 ml-1">
                      {stat.suffix}
                    </span>
                  )}
                </p>
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
}

