17→  "won", "isn", "aren", "wasn", "weren", "hasn", "hadn", "couldn",
18→  "wouldn", "shouldn", "ve", "re", "ll", "don't", "didn't", "doesn't",
19→  "product", "item", "thing", "things", "bought", "buy", "purchasing",
20→]);
