 45→
 46→    const stream = new ReadableStream({
 47→      async start(controller) {
 48→        try {
 49→          const generator = streamBedrockResponse({
 50→            systemPrompt,
 51→            messages,
 52→            guardrailId,
 53→            guardrailVersion,
 54→          });
 55→
 56→          for await (const chunk of generator) {
 57→            if (chunk.type === "text") {
 58→              controller.enqueue(
 59→                encoder.encode(
 60→                  `data: ${JSON.stringify({ type: "text", content: chunk.text })}\n\n`
 61→                )
 62→              );
 63→            } else if (chunk.type === "guard") {
 64→              controller.enqueue(
 65→                encoder.encode(
 66→                  `data: ${JSON.stringify({ type: "guard", action: chunk.action, content: chunk.message })}\n\n`
 67→                )
 68→              );
 69→            }
 70→          }
 71→
 72→          controller.enqueue(
 73→            encoder.encode(`data: ${JSON.stringify({ type: "done" })}\n\n`)
 74→          );
 75→        } catch (error) {
 76→          console.error("Bedrock streaming error:", error);
 77→
 78→          // Check if it's a guardrail intervention (Bedrock throws on blocked)
 79→          const errorMessage = error instanceof Error ? error.message : String(error);
 80→          if (
 81→            errorMessage.includes("guardrail") ||
 82→            errorMessage.includes("GUARDRAIL")
 83→          ) {
 84→            controller.enqueue(
 85→              encoder.encode(
 86→                `data: ${JSON.stringify({
 87→                  type: "guard",
 88→                  action: "BLOCKED",
 89→                  content: `I can only analyze the ${session.metadata.totalReviews} ${session.metadata.platform} reviews loaded for **${session.metadata.productName}**. That question falls outside the scope of the ingested review data. Feel free to ask me anything about the reviews!`,
 90→                })}\n\n`
 91→              )
 92→            );
 93→          } else {
 94→            controller.enqueue(
 95→              encoder.encode(
 96→                `data: ${JSON.stringify({
 97→                  type: "error",
 98→                  content: "An error occurred while generating a response. Please try again.",
 99→                })}\n\n`
100→              )
101→            );
102→          }
103→
104→          controller.enqueue(
105→            encoder.encode(`data: ${JSON.stringify({ type: "done" })}\n\n`)
106→          );
107→        } finally {
108→          controller.close();
109→        }
110→      },
111→    });
112→
113→    return new Response(stream, {
114→      headers: {
115→        "Content-Type": "text/event-stream",
116→        "Cache-Control": "no-cache",
117→        Connection: "keep-alive",
118→      },
119→    });
120→  } catch (error) {
121→    console.error("Chat route error:", error);
122→    return new Response(
123→      JSON.stringify({ error: "Failed to process chat request" }),
124→      { status: 500, headers: { "Content-Type": "application/json" } }
125→    );
126→  }
127→}
