 23→const SUGGESTED_QUESTIONS = [
 24→  "What are the most common complaints?",
 25→  "Summarize the positive reviews",
 26→  "What do customers say about quality?",
 27→  "Are there any recurring issues?",
 28→  "What features do reviewers mention most?",
 29→  "Compare 5-star vs 1-star review themes",
 30→];
