 32→export default function ChatInterface({ sessionId, metadata }: ChatInterfaceProps) {
 33→  const [messages, setMessages] = useState<ChatMessage[]>([]);
 34→  const [input, setInput] = useState("");
 35→  const [isStreaming, setIsStreaming] = useState(false);
 36→  const scrollRef = useRef<HTMLDivElement>(null);
 37→  const textareaRef = useRef<HTMLTextAreaElement>(null);
 38→
 39→  useEffect(() => {
 40→    if (scrollRef.current) {
 41→      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
 42→    }
 43→  }, [messages]);
 44→
 45→  const sendMessage = async (messageText?: string) => {
 46→    const text = messageText || input.trim();
 47→    if (!text || isStreaming) return;
 48→
 49→    const userMessage: ChatMessage = {
 50→      id: crypto.randomUUID(),
 51→      role: "user",
 52→      content: text,
 53→      timestamp: new Date().toISOString(),
 54→    };
 55→
 56→    setMessages((prev) => [...prev, userMessage]);
 57→    setInput("");
 58→    setIsStreaming(true);
 59→
 60→    const assistantId = crypto.randomUUID();
 61→    const assistantMessage: ChatMessage = {
 62→      id: assistantId,
 63→      role: "assistant",
 64→      content: "",
 65→      timestamp: new Date().toISOString(),
 66→    };
 67→    setMessages((prev) => [...prev, assistantMessage]);
 68→
 69→    try {
 70→      const history = messages.map((m) => ({
 71→        role: m.role,
 72→        content: m.content,
 73→      }));
 74→
 75→      const response = await fetch("/api/chat", {
 76→        method: "POST",
 77→        headers: { "Content-Type": "application/json" },
 78→        body: JSON.stringify({ sessionId, message: text, history }),
 79→      });
 80→
 81→      if (!response.ok) throw new Error("Chat request failed");
 82→
 83→      const reader = response.body?.getReader();
 84→      if (!reader) throw new Error("No response stream");
 85→
 86→      const decoder = new TextDecoder();
 87→      let buffer = "";
 88→
 89→      while (true) {
 90→        const { done, value } = await reader.read();
 91→        if (done) break;
 92→
 93→        buffer += decoder.decode(value, { stream: true });
 94→        const lines = buffer.split("\n\n");
 95→        buffer = lines.pop() || "";
 96→
 97→        for (const line of lines) {
 98→          if (!line.startsWith("data: ")) continue;
 99→          try {
100→            const data = JSON.parse(line.slice(6));
101→            if (data.type === "text") {
102→              setMessages((prev) =>
103→                prev.map((m) =>
104→                  m.id === assistantId ? { ...m, content: m.content + data.content } : m
105→                )
106→              );
107→            } else if (data.type === "guard") {
108→              setMessages((prev) =>
109→                prev.map((m) =>
110→                  m.id === assistantId
111→                    ? { ...m, content: data.content, scopeGuardTriggered: true, guardrailAction: data.action }
112→                    : m
113→                )
114→              );
115→            } else if (data.type === "error") {
116→              setMessages((prev) =>
117→                prev.map((m) =>
118→                  m.id === assistantId ? { ...m, content: data.content } : m
119→                )
120→              );
121→            }
122→          } catch {
123→            /* skip invalid JSON */
124→          }
125→        }
126→      }
127→    } catch {
128→      setMessages((prev) =>
129→        prev.map((m) =>
130→          m.id === assistantId
131→            ? { ...m, content: "Sorry, something went wrong. Please try again." }
132→            : m
133→        )
134→      );
135→    } finally {
136→      setIsStreaming(false);
137→    }
138→  };
139→
140→  const handleKeyDown = (e: React.KeyboardEvent) => {
141→    if (e.key === "Enter" && !e.shiftKey) {
142→      e.preventDefault();
143→      sendMessage();
144→    }
145→  };
146→
147→  return (
148→    <div className="flex flex-col h-[calc(100vh-10rem)]">
149→      {/* Chat header */}
150→      <div className="glass-card rounded-xl px-4 py-3 mb-4 flex items-center gap-3">
151→        <div className="w-9 h-9 rounded-lg bg-linear-to-br from-emerald-500 to-green-600 flex items-center justify-center shadow-lg shadow-emerald-500/20">
152→          <Shield className="w-4 h-4 text-white" />
153→        </div>
154→        <div>
155→          <p className="text-sm font-semibold text-white/90">
156→            Guardrailed Q&A — {metadata.productName}
157→          </p>
158→          <p className="text-xs text-white/35">
159→            {metadata.totalReviews} {metadata.platform} reviews &middot; Dual-layer scope guard active
160→          </p>
161→        </div>
162→      </div>
163→
164→      {/* Messages area */}
165→      <ScrollArea className="flex-1 pr-4" ref={scrollRef}>
166→        <div className="space-y-4 pb-4">
167→          {messages.length === 0 && (
168→            <div className="text-center py-16 animate-fade-in">
169→              <div className="w-16 h-16 rounded-2xl bg-linear-to-br from-violet-500/20 to-indigo-500/20 flex items-center justify-center mx-auto mb-5 border border-violet-500/10">
170→                <Bot className="w-8 h-8 text-violet-400" />
171→              </div>
172→              <h3 className="text-lg font-semibold text-white/80 mb-2">
173→                Ask about the reviews
174→              </h3>
175→              <p className="text-sm text-white/35 mb-8 max-w-md mx-auto">
176→                I can analyze the {metadata.totalReviews} ingested {metadata.platform} reviews for{" "}
177→                <strong className="text-white/60">{metadata.productName}</strong>. I&apos;m scoped exclusively to this data.
178→              </p>
179→              <div className="flex flex-wrap gap-2 justify-center max-w-lg mx-auto">
180→                {SUGGESTED_QUESTIONS.map((q) => (
181→                  <button
182→                    key={q}
183→                    onClick={() => sendMessage(q)}
184→                    className="text-xs px-3.5 py-2 rounded-full glass hover:bg-violet-500/10 hover:border-violet-500/20 transition-all duration-200 text-white/50 hover:text-violet-300"
185→                  >
186→                    <Sparkles className="w-3 h-3 inline mr-1.5 text-violet-400" />
187→                    {q}
188→                  </button>
189→                ))}
190→              </div>
191→            </div>
192→          )}
193→
194→          {messages.map((msg) => (
195→            <div
196→              key={msg.id}
197→              className={cn(
198→                "flex gap-3 animate-fade-up",
199→                msg.role === "user" ? "justify-end" : "justify-start"
200→              )}
201→            >
202→              {msg.role === "assistant" && (
203→                <div
204→                  className={cn(
205→                    "w-8 h-8 rounded-lg flex items-center justify-center shrink-0",
206→                    msg.scopeGuardTriggered
207→                      ? "bg-red-500/20 border border-red-500/20"
208→                      : "bg-violet-500/20 border border-violet-500/20"
209→                  )}
210→                >
211→                  {msg.scopeGuardTriggered ? (
212→                    <ShieldAlert className="w-4 h-4 text-red-400" />
213→                  ) : (
214→                    <Bot className="w-4 h-4 text-violet-400" />
215→                  )}
216→                </div>
217→              )}
218→
219→              <div
220→                className={cn(
221→                  "max-w-[80%] rounded-xl px-4 py-3",
222→                  msg.role === "user"
223→                    ? "bg-linear-to-r from-violet-600 to-indigo-600 text-white shadow-lg shadow-violet-500/15"
224→                    : msg.scopeGuardTriggered
225→                    ? "glass border-red-500/20 bg-red-500/5 glow-red"
226→                    : "glass"
227→                )}
228→              >
229→                {msg.scopeGuardTriggered && (
230→                  <div className="flex items-center gap-1.5 mb-2">
