232→                    <span className="text-[10px] font-semibold text-red-400 uppercase tracking-wider">
233→                      Scope Guard — Out of Scope
234→                    </span>
235→                  </div>
236→                )}
237→                <div className={cn(
238→                  "text-sm whitespace-pre-wrap leading-relaxed",
239→                  msg.role === "user" ? "text-white" : "text-white/70"
240→                )}>
241→                  {msg.content ||
242→                    (isStreaming && msg.role === "assistant" ? (
243→                      <div className="flex items-center gap-1.5">
244→                        <div className="w-1.5 h-1.5 rounded-full bg-violet-400 animate-pulse" />
245→                        <div className="w-1.5 h-1.5 rounded-full bg-violet-400 animate-pulse delay-100" />
246→                        <div className="w-1.5 h-1.5 rounded-full bg-violet-400 animate-pulse delay-200" />
247→                      </div>
