 14→        { status: 400, headers: { "Content-Type": "application/json" } }
 15→      );
 16→    }
 17→
 18→    // Try in-memory store first; if missing, hydrate from client-provided sessionData
 19→    let session = getSession(sessionId);
 20→
 21→    if (!session && sessionData) {
 22→      const restored: ReviewSession = {
 23→        sessionId,
 24→        reviews: sessionData.reviews,
 25→        metadata: sessionData.metadata,
 26→        analytics: sessionData.analytics,
 27→      };
 28→      setSession(sessionId, restored);
 29→      session = restored;
 30→    }
 31→
 32→    if (!session) {
 33→      return new Response(
 34→        JSON.stringify({
 35→          error: "Session not found. Please ingest reviews first.",
 36→        }),
 37→        { status: 404, headers: { "Content-Type": "application/json" } }
 38→      );
 39→    }
 40→
 41→    // Build system prompt with review context
 42→    const systemPrompt = buildSystemPrompt(session.metadata, session.reviews);
 43→
 44→    // Build conversation messages (include history for context)
 45→    const messages = [
 46→      ...history.map((h: { role: string; content: string }) => ({
 47→        role: h.role as "user" | "assistant",
 48→        content: h.content,
 49→      })),
 50→      { role: "user" as const, content: message },
 51→    ];
 52→
 53→    // Stream response using Bedrock with Guardrails
 54→    const guardrailId = process.env.BEDROCK_GUARDRAIL_ID;
 55→    const guardrailVersion = process.env.BEDROCK_GUARDRAIL_VERSION || "DRAFT";
 56→
 57→    const encoder = new TextEncoder();
 58→
 59→    // Use TransformStream for proper chunk-by-chunk flushing
 60→    const { readable, writable } = new TransformStream();
 61→    const writer = writable.getWriter();
 62→
 63→    // Run the streaming in the background — the response is returned immediately
 64→    (async () => {
 65→      try {
 66→        const generator = streamBedrockResponse({
 67→          systemPrompt,
 68→          messages,
 69→          guardrailId,
 70→          guardrailVersion,
 71→        });
 72→
 73→        for await (const chunk of generator) {
 74→          if (chunk.type === "text") {
 75→            await writer.write(
 76→              encoder.encode(
 77→                `data: ${JSON.stringify({ type: "text", content: chunk.text })}\n\n`
 78→              )
 79→            );
 80→          } else if (chunk.type === "guard") {
 81→            await writer.write(
 82→              encoder.encode(
 83→                `data: ${JSON.stringify({ type: "guard", action: chunk.action, content: chunk.message })}\n\n`
 84→              )
 85→            );
 86→          }
 87→        }
 88→
 89→        await writer.write(
 90→          encoder.encode(`data: ${JSON.stringify({ type: "done" })}\n\n`)
 91→        );
 92→      } catch (error) {
 93→        console.error("Bedrock streaming error:", error);
 94→
 95→        const errorMessage = error instanceof Error ? error.message : String(error);
