export const dynamic = "force-dynamic";

const encoder = new TextEncoder();

async function* makeChunks() {
  for (let i = 0; i < 10; i++) {
    yield encoder.encode(`data: ${JSON.stringify({ type: "text", content: `Chunk ${i + 1} ` })}\n\n`);
    await new Promise((r) => setTimeout(r, 300));
  }
  yield encoder.encode(`data: ${JSON.stringify({ type: "done" })}\n\n`);
}

function iteratorToStream(iterator: AsyncGenerator<Uint8Array, void, unknown>) {
  return new ReadableStream({
    async pull(controller) {
      const { value, done } = await iterator.next();
      if (done) {
        controller.close();
      } else {
        controller.enqueue(value);
      }
    },
  });
}

export async function GET() {
  const stream = iteratorToStream(makeChunks());
  return new Response(stream, {
    headers: {
      "Content-Type": "text/event-stream; charset=utf-8",
      "Cache-Control": "no-cache, no-transform",
      "X-Content-Type-Options": "nosniff",
    },
  });
}

