const response = await fetch("/api/chat", {
  method: "POST",
  headers: {
    "Content-Type": "application/json",
    "Accept-Encoding": "identity",
    "Accept": "text/event-stream",
  },
  body: JSON.stringify({ sessionId, message: text, history, sessionData }),
});

if (!response.ok) throw new Error("Chat request failed");

const reader = response.body?.getReader();
if (!reader) throw new Error("No response stream");

const decoder = new TextDecoder();
let buffer = "";

// Process each chunk as it arrives from the stream
for (;;) {
  const { done, value } = await reader.read();
  if (done) break;

  buffer += decoder.decode(value, { stream: true });

  // Process all complete SSE messages in this chunk
  let boundary = buffer.indexOf("\n\n");
  while (boundary !== -1) {
    const line = buffer.slice(0, boundary);
    buffer = buffer.slice(boundary + 2);

    if (line.startsWith("data: ")) {
      try {
        const data = JSON.parse(line.slice(6));
        if (data.type === "text") {
          setMessages((prev) =>
            prev.map((m) =>
              m.id === assistantId ? { ...m, content: m.content + data.content } : m
            )
          );
        } else if (data.type === "guard") {
          setMessages((prev) =>
            prev.map((m) =>
              m.id === assistantId
                ? { ...m, content: data.content, scopeGuardTriggered: true, guardrailAction: data.action }
                : m
            )
          );
        } else if (data.type === "error") {
          setMessages((prev) =>
            prev.map((m) =>
