"use client";

import {
  PieChart,
  Pie,
  Cell,
  ResponsiveContainer,
  Legend,
  Tooltip,
} from "recharts";

interface SentimentChartProps {
  breakdown: {
    positive: number;
    negative: number;
    neutral: number;
    mixed: number;
  };
}

const COLORS = {
