            {review.verified && (
              <span className="flex items-center gap-1 text-emerald-400/60">
                <CheckCircle2 className="w-3 h-3" />
                Verified
              </span>
            )}
            {review.date && <span>{review.date}</span>}
          </div>
        </div>
      </div>
    </div>
  );
}

