 1→import { parse } from "csv-parse/sync";
 2→import { Review } from "@/types";
 3→import { v4 as uuidv4 } from "uuid";
 4→
 5→export function parseCSV(csvContent: string): Review[] {
 6→  const records = parse(csvContent, {
 7→    columns: true,
 8→    skip_empty_lines: true,
 9→    trim: true,
10→    relax_column_count: true,
11→  });
12→
13→  return (records as Record<string, string>[]).map((record) => {
14→    // Support various column name formats
15→    const rating = parseFloat(
16→      record.rating || record.Rating || record.stars || record.Stars || record.score || "0"
17→    );
18→    const title =
19→      record.title || record.Title || record.headline || record.Headline || "";
20→    const body =
21→      record.body ||
22→      record.Body ||
23→      record.text ||
24→      record.Text ||
25→      record.review ||
26→      record.Review ||
27→      record.content ||
28→      record.Content ||
29→      "";
30→    const date =
31→      record.date || record.Date || record.timestamp || record.Timestamp || "";
32→    const reviewer =
33→      record.reviewer ||
34→      record.Reviewer ||
35→      record.author ||
36→      record.Author ||
37→      record.name ||
38→      record.Name ||
39→      "Anonymous";
40→    const verified =
41→      (record.verified || record.Verified || "").toLowerCase() === "true";
42→
43→    return {
44→      id: uuidv4(),
45→      rating: Math.min(5, Math.max(0, rating)),
46→      title: title.trim(),
47→      body: body.trim(),
48→      date: date.trim(),
49→      reviewer: reviewer.trim(),
50→      verified,
51→    } satisfies Review;
52→  });
53→}
