 43→async function apifyFetch(path: string, options?: RequestInit): Promise<Response> {
 44→  const token = process.env.APIFY_API_TOKEN;
 45→  if (!token) {
 46→    throw new Error("APIFY_API_TOKEN not configured");
 47→  }
 48→  const url = `${APIFY_BASE_URL}${path}${path.includes("?") ? "&" : "?"}token=${token}`;
 49→  return fetch(url, options);
 50→}
