 52→async function waitForRun(runId: string, actorId: string, timeoutMs = 120000): Promise<ApifyRunResponse["data"]> {
 53→  const start = Date.now();
 54→  while (Date.now() - start < timeoutMs) {
 55→    const res = await apifyFetch(`/acts/${actorId}/runs/${runId}`);
 56→    const data = (await res.json()) as ApifyRunResponse;
 57→    if (data.data.status === "SUCCEEDED") return data.data;
 58→    if (data.data.status === "FAILED" || data.data.status === "ABORTED") {
 59→      throw new Error(`Apify run ${data.data.status.toLowerCase()}`);
 60→    }
 61→    await new Promise((r) => setTimeout(r, 3000));
 62→  }
 63→  throw new Error("Apify run timed out");
 64→}
