 26→export async function POST(request: NextRequest) {
 27→  try {
 28→    const { sessionId, message, history = [], sessionData } =
 29→      await request.json();
 30→
 31→    if (!sessionId || !message) {
 32→      return new Response(
 33→        JSON.stringify({ error: "sessionId and message are required" }),
 34→        { status: 400, headers: { "Content-Type": "application/json" } }
 35→      );
 36→    }
 37→
 38→    // Try in-memory store first; if missing, hydrate from client-provided sessionData
 39→    let session = getSession(sessionId);
 40→
 41→    if (!session && sessionData) {
 42→      const restored: ReviewSession = {
 43→        sessionId,
 44→        reviews: sessionData.reviews,
 45→        metadata: sessionData.metadata,
 46→        analytics: sessionData.analytics,
 47→      };
 48→      setSession(sessionId, restored);
 49→      session = restored;
 50→    }
 51→
 52→    if (!session) {
 53→      return new Response(
 54→        JSON.stringify({
 55→          error: "Session not found. Please ingest reviews first.",
 56→        }),
 57→        { status: 404, headers: { "Content-Type": "application/json" } }
 58→      );
 59→    }
 60→
 61→    // Build system prompt with review context
 62→    const systemPrompt = buildSystemPrompt(session.metadata, session.reviews);
 63→
 64→    // Build conversation messages (include history for context)
 65→    const messages = [
 66→      ...history.map((h: { role: string; content: string }) => ({
 67→        role: h.role as "user" | "assistant",
 68→        content: h.content,
 69→      })),
 70→      { role: "user" as const, content: message },
 71→    ];
 72→
 73→    // Stream response using Bedrock with Guardrails
 74→    const guardrailId = process.env.BEDROCK_GUARDRAIL_ID;
 75→    const guardrailVersion = process.env.BEDROCK_GUARDRAIL_VERSION || "DRAFT";
 76→
 77→    const encoder = new TextEncoder();
 78→    const confirmedSession = session;
 79→
 80→    // Async generator that yields SSE-encoded chunks
 81→    async function* makeSSEIterator(): AsyncGenerator<
 82→      Uint8Array,
 83→      void,
 84→      unknown
 85→    > {
 86→      try {
 87→        const generator = streamBedrockResponse({
 88→          systemPrompt,
 89→          messages,
 90→          guardrailId,
 91→          guardrailVersion,
 92→        });
 93→
 94→        for await (const chunk of generator) {
 95→          if (chunk.type === "text") {
 96→            yield encoder.encode(
 97→              `data: ${JSON.stringify({ type: "text", content: chunk.text })}\n\n`
 98→            );
 99→          } else if (chunk.type === "guard") {
100→            yield encoder.encode(
101→              `data: ${JSON.stringify({ type: "guard", action: chunk.action, content: chunk.message })}\n\n`
102→            );
103→          }
104→        }
105→
106→        yield encoder.encode(
107→          `data: ${JSON.stringify({ type: "done" })}\n\n`
108→        );
109→      } catch (error) {
110→        console.error("Bedrock streaming error:", error);
111→
112→        const errorMessage =
113→          error instanceof Error ? error.message : String(error);
114→        if (
115→          errorMessage.includes("guardrail") ||
116→          errorMessage.includes("GUARDRAIL")
117→        ) {
118→          yield encoder.encode(
119→            `data: ${JSON.stringify({
120→              type: "guard",
121→              action: "BLOCKED",
122→              content: `I can only analyze the ${confirmedSession.metadata.totalReviews} ${confirmedSession.metadata.platform} reviews loaded for **${confirmedSession.metadata.productName}**. That question falls outside the scope of the ingested review data. Feel free to ask me anything about the reviews!`,
123→            })}\n\n`
124→          );
125→        } else {
126→          yield encoder.encode(
127→            `data: ${JSON.stringify({
128→              type: "error",
129→              content:
130→                "An error occurred while generating a response. Please try again.",
131→            })}\n\n`
132→          );
133→        }
134→
135→        yield encoder.encode(
136→          `data: ${JSON.stringify({ type: "done" })}\n\n`
137→        );
138→      }
139→    }
140→
141→    const stream = iteratorToStream(makeSSEIterator());
142→
143→    return new Response(stream, {
144→      headers: {
145→        "Content-Type": "text/event-stream; charset=utf-8",
146→        "Cache-Control": "no-cache, no-transform",
147→        Connection: "keep-alive",
148→        "X-Content-Type-Options": "nosniff",
149→      },
150→    });
151→  } catch (error) {
152→    console.error("Chat route error:", error);
153→    return new Response(
154→      JSON.stringify({ error: "Failed to process chat request" }),
155→      { status: 500, headers: { "Content-Type": "application/json" } }
156→    );
157→  }
158→}
