 3→
 4→export async function GET(request: NextRequest) {
 5→  const sessionId = request.nextUrl.searchParams.get("sessionId");
 6→
 7→  if (!sessionId) {
 8→    return NextResponse.json(
 9→      { error: "sessionId is required" },
10→      { status: 400 }
11→    );
12→  }
13→
14→  const session = getSession(sessionId);
15→
16→  if (!session) {
17→    return NextResponse.json(
18→      { error: "Session not found. Please ingest reviews first." },
19→      { status: 404 }
20→    );
21→  }
22→
23→  return NextResponse.json({
24→    reviews: session.reviews,
25→    metadata: session.metadata,
26→  });
27→}
